"from models.schemas import ClaimExtractionResult, VisionInspectionResult

class ObjectPartAgent:
    def __init__(self):
        pass

    def verify_part(self, extraction: ClaimExtractionResult, vision: VisionInspectionResult) -> str:
        # Deterministic verification if the part extracted matches the part seen
        if extraction.object_part == "unknown" and vision.visible_object_part != "unknown":
            return vision.visible_object_part

        if extraction.object_part == vision.visible_object_part:
            return extraction.object_part

        if vision.visible_object_part == "unknown":
            return extraction.object_part # Give benefit of doubt to extraction if vision can't tell but damage is found

        # If they disagree, we might have a wrong_object_part risk, handled in decision.
        return vision.visible_object_part
"

"from typing import List, Dict
from models.schemas import UserHistory, RiskFlag

class RiskAssessmentAgent:
    def __init__(self, history_data: List[UserHistory]):
        self.history_map = {h.user_id: h for h in history_data}

    def assess_risk(self, user_id: str) -> List[RiskFlag]:
        user_history = self.history_map.get(user_id)
        if not user_history:
            return [RiskFlag.none]

        flags = []
        if "user_history_risk" in user_history.history_flags:
            flags.append(RiskFlag.user_history_risk)
        if "manual_review_required" in user_history.history_flags:
            flags.append(RiskFlag.manual_review_required)

        if not flags:
            return [RiskFlag.none]
        return flags
"

"import json
import os
import hashlib
from typing import Any, Optional

class CacheService:
    def __init__(self, cache_dir: str = ".cache"):
        self.cache_dir = cache_dir
        if not os.path.exists(self.cache_dir):
            os.makedirs(self.cache_dir)

    def _generate_key(self, prefix: str, data: str) -> str:
        # Create a deterministic hash for the input data
        hash_val = hashlib.md5(data.encode('utf-8')).hexdigest()
        return os.path.join(self.cache_dir, f"{prefix}_{hash_val}.json")

    def get(self, prefix: str, data: str) -> Optional[dict]:
        filepath = self._generate_key(prefix, data)
        if os.path.exists(filepath):
            try:
                with open(filepath, 'r') as f:
                    return json.load(f)
            except:
                pass
        return None

    def set(self, prefix: str, data: str, result: dict):
        filepath = self._generate_key(prefix, data)
        with open(filepath, 'w') as f:
            json.dump(result, f)
"

